/**
 * Adapted Legacy Template
 * Womens Hormone Imbalance
 *
 * This bundle includes:
 * - Multi-select quiz system (5 questions)
 * - Reviews carousel with expand/collapse
 * - Product actions carousel (Slick)
 * - Infographic carousel WITH biomarkers
 * - FAQ accordion
 * - Parallax marquee effect for disease rows
 */

// Import utilities
import { initStickyCTA } from '../utilities/stickyCTA.js';
import { initCarousel } from '../utilities/carousel.js';

// Export to window
window.initStickyCTA = initStickyCTA;
window.initCarousel = initCarousel;

/**
 * =============================
 * QUIZ DATA & CONFIGURATION
 * =============================
 */

const quizData = [
	{
		"id": 1,
		"type": "single-select",
		"title": "What's your biggest health goal?",
		"options": [
			{ "id": 0, "value": "Get relief for existing condition" },
			{ "id": 1, "value": "Understand my hormone levels" },
			{ "id": 2, "value": "Talk to a doctor about my symptoms" },
			{ "id": 3, "value": "Optimize my health" }
		]
	},
	{
		"id": 2,
		"type": "multi-select",
		"title": "What's holding you back<br class='is-visible-tablet-only' /> from feeling your best? <span class='select-all'>(Select all that apply)</span>",
		"ctaText": "Next Question",
		"options": [
			{ "id": 0, "value": "Fatigue" },
			{ "id": 1, "value": "Brain Fog" },
			{ "id": 2, "value": "Weight gain" },
			{ "id": 3, "value": "Low libido" },
			{ "id": 4, "value": "Mood swings" },
			{ "id": 5, "value": "Night sweats" },
			{ "id": 6, "value": "Hair loss" },
			{ "id": 7, "value": "Irregular periods" },
			{ "id": 8, "value": "None" }
		]
	},
	{
		"id": 3,
		"type": "multi-select",
		"title": "What about long-term health concerns? <span class='select-all'>(Select all that apply)</span>",
		"ctaText": "Next Question",
		"options": [
			{ "id": 0, "value": "Blood sugar issues" },
			{ "id": 1, "value": "Chronic inflammation" },
			{ "id": 2, "value": "Environmental stress" },
			{ "id": 3, "value": "Vitamin deficiencies" },
			{ "id": 4, "value": "Too much stress" },
			{ "id": 5, "value": "None" }
		]
	},
	{
		"id": 4,
		"type": "multi-select",
		"title": "Is your sex life where you want it to be? <span class='select-all'>(Select all that apply)</span>",
		"ctaText": "Next Question",
		"options": [
			{ "id": 0, "value": "No drive" },
			{ "id": 1, "value": "Could use a boost" },
			{ "id": 2, "value": "Dryness is an issue" },
			{ "id": 3, "value": "Discomfort or pain" },
			{ "id": 4, "value": "No problems here" }
		]
	},
	{
		"id": 5,
		"type": "single-select",
		"title": "How familiar are you with hormone&nbsp;therapy?",
		"options": [
			{ "id": 0, "value": "New to this" },
			{ "id": 1, "value": "Know a little, want more info" },
			{ "id": 2, "value": "Informed and comparing options" }
		]
	}
];

const quizResultContent = [
	{
		"header": "We've got you covered",
		"body": "You deserve to understand what's happening with your body, and Hone's got your back. Your licensed doctor will guide you through everything, from hormone balancing basics to creating a custom plan that fits your life. No more guesswork, just real answers."
	},

