/**
 * Sticky CTA Utility
 * ==================
 * 
 * HOW TO FIND THE RIGHT SCROLL TRIGGER VALUE:
 * 1. Add temporary debug code to your page:
 *    ```javascript
 *    window.addEventListener('scroll', () => console.log('Scroll:', window.scrollY));
 *    ```
 * 2. Open browser DevTools console (F12)
 * 3. Scroll to where you want the CTA to appear
 * 4. Note the scroll position value
 * 5. Use that value as scrollTrigger parameter
 * 6. Remove the debug code
 * 
 * EXPORTS:
 * - initStickyCTA(scrollTrigger, selector)
 * 
 * USAGE:
 * ```javascript
 * # Basic usage - show after scrolling 1340px
 * initStickyCTA(1340);
 * 
 * # Custom selector
 * initStickyCTA(2000, '.my-custom-banner');
 * 
 * # ES Module import
 * import { initStickyCTA } from './utilities/stickyCTA.js';
 * initStickyCTA(800);
 * ```
 * 
 * @param {number} scrollTrigger - Scroll position (px) at which to show the sticky CTA
 * @param {string} [selector='.stickycta-section'] - CSS selector for the sticky element
 */
function initStickyCTA(scrollTrigger, selector = '.stickycta-section') {
	const stickyElement = document.querySelector(selector);

	if (!stickyElement) {
		console.warn(`Sticky CTA element not found: ${selector}`);
		return;
	}

	function updateStickyState() {
		const scrollPosition = window.scrollY;
		const windowHeight = window.innerHeight;
		const bodyHeight = document.body.offsetHeight;
		const bannerHeight = stickyElement.offsetHeight;

		// Hide when near bottom of page
		if (scrollPosition + windowHeight >= bodyHeight - bannerHeight) {
			stickyElement.classList.remove("show");
		}
		// Show when past scroll trigger
		else if (scrollPosition > scrollTrigger) {
			stickyElement.classList.add("show");
		}
		// Hide when above scroll trigger
		else {
			stickyElement.classList.remove("show");
		}
	}

	// Add scroll listener
	window.addEventListener("scroll", updateStickyState);

	// Initial check
	updateStickyState();
}

// Make function available globally (for non-bundled usage)
if (typeof window !== 'undefined') {
	window.initStickyCTA = initStickyCTA;
}

// ES module export (for bundled usage)
export { initStickyCTA };

