/**
* =============================
* MONITOR INDICATORS PARALLAX STYLES
* =============================
*/
@mixin monitor-indicators-parallax {
.monitor-for-early-indicators {
	max-width: 1920px;
	margin-inline: auto;
	width: 100%;
	.container {
		margin: 3rem 4rem;
		border-radius: 20px;
		background: linear-gradient(90deg, rgba(96, 91, 82, 0.20) 0.06%, rgba(96, 91, 82, 0.06) 99.83%), #FFF;
		/* overrides */
		padding: 0;
		max-width: unset;
		width: unset;
		@media only screen and (max-width: 1024px) {
			margin: 1.5rem 2.5rem;
		}
		@media only screen and (max-width: 768px) {
			margin: 1.5rem 1rem;
		}
	}
	.wrapper {
		padding: 4rem;
	}
	.graphic-wrapper {
		padding-top: 4rem;
		padding-inline: 0;
		padding-bottom: 0;
		@media only screen and (max-width: 768px) {
			padding-top: 2rem;
		}
		h2 {
			font-family: 'STIX Two Text', serif;
			font-size: 2.25rem;
			font-weight: 400;
			line-height: 1;
			letter-spacing: -0.72px;
			padding-inline: 4rem;
			text-align: center;
			margin-bottom: 2.5rem;
			@media only screen and (max-width: 1024px) {
				font-size: 1.8125rem;
				line-height: 96%;
				letter-spacing: -0.29px;
				padding-inline: 1rem;
			}
			@media only screen and (max-width: 768px) {
				margin-bottom: 1.5rem;
			}
		}
	}
	.content-block {
		max-width: 100%;
	}
	.disease-list {
		display: flex;
		flex-direction: column;
		gap: 0.75rem;
		margin-bottom: 2.5rem;
		@media only screen and (max-width: 1024px) {
			margin-bottom: 0;
			gap: 0.5rem;
		}
	}

	.disease-row-wrapper {
		overflow-x: hidden;
		overflow-y: visible;
		width: 100%;
		max-width: 100vw;
	}

	.disease-row-container {
		width: 100%;
		overflow-x: hidden;
		overflow-y: visible;
	}

	.disease-row-list {
		display: flex;
		white-space: nowrap;
		will-change: transform;
		transform: translateX(0);
		transition: none;
		gap: 0.75rem;
		@media only screen and (max-width: 1024px) {
			gap: 0.5rem;
		}

		.disease-item {
			display: inline-block;
			padding: 0.6875rem 1rem;
			background-color: #FFF;
			backdrop-filter: blur(7.5px);
			border-radius: 5px;
			font-family: 'DM Sans', sans-serif;
			font-weight: 500;
			font-size: 1.375rem;
			line-height: 1;
			letter-spacing: -0.44px;
			color: #0E0B20;
			white-space: nowrap;
			border: 1px solid rgba(96, 91, 82, 0.1);
			flex-shrink: 0;
			@media only screen and (max-width: 1024px) {
				padding: 0.5rem 0.75rem;
				font-size: 1.125rem;
				line-height: 1;
				letter-spacing: -0.36px;
			}
		}
	}

	.graphic-block {
		display: flex;
		justify-content: center;
		align-items: center;		
		@media only screen and (max-width: 768px) {
			padding-bottom: 1.5rem;
		}

		img {
			max-width: 100%;
			width: 720px;
			height: auto;
			display: block;
			@media only screen and (max-width: 768px) {
				width: 100%;
			}
		}
	} 
}
}

