     1→/**
     2→ * Carousel Utility
     3→ * ================
     4→ * 
     5→ * DEPENDENCIES:
     6→ * - jQuery (must be loaded before this script)
     7→ * - Slick Slider (https://kenwheeler.github.io/slick/)
     8→ * 
     9→ * DEFAULT SLICK CONFIG (can be overridden via carouselParams):
    10→ * - slidesToShow: 1
    11→ * - slidesToScroll: 1
    12→ * - infinite: false
    13→ * - dots: false
    14→ * - arrows: false
    15→ * 
    16→ * EXPORTS:
    17→ * - initCarousel(carouselParams, carouselPrefix, enableSwipeIndicator)
    18→ * 
    19→ * USAGE:
    20→ * ```javascript
    21→ * # Basic usage
    22→ * initCarousel({}, '.testimonials');
    23→ * 
    24→ * # With custom Slick options
    25→ * initCarousel({ infinite: true, autoplay: true }, '.hero');
    26→ * 
    27→ * # With swipe indicator
    28→ * initCarousel({}, '.products', true);
    29→ * ```
    30→ * 
    31→ * @param {Object} carouselParams - Configuration object for Slick carousel (merged with defaults)
    32→ * @param {string} carouselPrefix - The prefix/selector for the carousel (e.g., '.testimonials')
    33→ * @param {boolean} enableSwipeIndicator - Enable swipe indicator hiding on interaction (default: false)
    34→ */
    35→function initCarousel(carouselParams, carouselPrefix, enableSwipeIndicator) {
    36→	// Ensure jQuery and Slick are available
    37→	if (typeof jQuery === 'undefined' || typeof jQuery.fn.slick === 'undefined') {
    38→		console.error('Carousel initialization requires jQuery and Slick slider');
    39→		return;
    40→	}
    41→
    42→	const $ = jQuery;
    43→
    44→	// Default swipeIndicator to false if not provided
    45→	const swipeIndicatorEnabled = enableSwipeIndicator || false;
    46→	
    47→	// Default Slick carousel configuration
    48→	const defaultParams = {
    49→		slidesToShow: 1,
    50→		slidesToScroll: 1,
    51→		infinite: false,
    52→		dots: false,
    53→		arrows: false,
    54→		focusOnSelect: false,
    55→		accessibility: false,
    56→		centerMode: false,
    57→		centerPadding: '0'
    58→	};
    59→
    60→	// Merge user params with defaults (user params override defaults)
    61→	const slickConfig = $.extend({}, defaultParams, carouselParams);
    62→
    63→	// Initialize Slick carousel with merged configuration
    64→	$(carouselPrefix + '-carousel').slick(slickConfig);
    65→
    66→	// Swipe indicator functionality (if enabled)
    67→	let hasInteracted = false;
    68→	const hideSwipeIndicator = function() {
    69→		if (!hasInteracted && swipeIndicatorEnabled) {
    70→			$('.swipe-indicator').addClass('hidden');
    71→			hasInteracted = true;
    72→		}
    73→	};
    74→
    75→	// Custom navigation for prev button
    76→	$(carouselPrefix + '-prev').on('click', function() {
    77→		$(carouselPrefix + '-carousel').slick('slickPrev');
    78→		if (swipeIndicatorEnabled) hideSwipeIndicator();
    79→	});
    80→	
    81→	// Custom navigation for next button
    82→	$(carouselPrefix + '-next').on('click', function() {
    83→		$(carouselPrefix + '-carousel').slick('slickNext');
    84→		if (swipeIndicatorEnabled) hideSwipeIndicator();
    85→	});
    86→	
    87→	// Custom navigation for dot indicators
    88→	$(carouselPrefix + '-dots .nav-dot').on('click', function() {
    89→		const slideIndex = $(this).data('slide');
    90→		$(carouselPrefix + '-carousel').slick('slickGoTo', slideIndex);
    91→		if (swipeIndicatorEnabled) hideSwipeIndicator();
    92→	});
    93→	
    94→	// Update active dot when slide changes
    95→	$(carouselPrefix + '-carousel').on('beforeChange', function(event, slick, currentSlide, nextSlide) {
    96→		$(carouselPrefix + '-dots .nav-dot').removeClass('active');
    97→		$(carouselPrefix + '-dots .nav-dot[data-slide="' + nextSlide + '"]').addClass('active');
    98→		if (swipeIndicatorEnabled) hideSwipeIndicator();
    99→	});
   100→
   101→	// Prevent carousel from triggering scroll events that affect sticky CTA
   102→	$(carouselPrefix + '-carousel').on('beforeChange afterChange', function(event, slick, currentSlide, nextSlide) {
   103→		event.stopPropagation();
   104→	});
   105→
   106→	// Hide swipe indicator on touch/swipe events (if enabled)
   107→	if (swipeIndicatorEnabled) {
   108→		$(carouselPrefix + '-carousel').on('touchstart swipe', hideSwipeIndicator);
   109→	}
   110→}
   111→
   112→// Make function available globally (for non-bundled usage)
   113→if (typeof window !== 'undefined') {
