/**
 * Carousel Utility
 * ================
 * 
 * DEPENDENCIES:
 * - jQuery (must be loaded before this script)
 * - Slick Slider (https://kenwheeler.github.io/slick/)
 * 
 * DEFAULT SLICK CONFIG (can be overridden via carouselParams):
 * - slidesToShow: 1
 * - slidesToScroll: 1
 * - infinite: false
 * - dots: false
 * - arrows: false
 * 
 * EXPORTS:
 * - initCarousel(carouselParams, carouselPrefix, enableSwipeIndicator)
 * 
 * USAGE:
 * ```javascript
 * # Basic usage
 * initCarousel({}, '.testimonials');
 * 
 * # With custom Slick options
 * initCarousel({ infinite: true, autoplay: true }, '.hero');
 * 
 * # With swipe indicator
 * initCarousel({}, '.products', true);
 * ```
 * 
 * @param {Object} carouselParams - Configuration object for Slick carousel (merged with defaults)
 * @param {string} carouselPrefix - The prefix/selector for the carousel (e.g., '.testimonials')
 * @param {boolean} enableSwipeIndicator - Enable swipe indicator hiding on interaction (default: false)
 */
function initCarousel(carouselParams, carouselPrefix, enableSwipeIndicator) {
	// Ensure jQuery and Slick are available
	if (typeof jQuery === 'undefined' || typeof jQuery.fn.slick === 'undefined') {
		console.error('Carousel initialization requires jQuery and Slick slider');
		return;
	}

	const $ = jQuery;

	// Default swipeIndicator to false if not provided
	const swipeIndicatorEnabled = enableSwipeIndicator || false;

	// Default Slick carousel configuration
	const defaultParams = {
		slidesToShow: 1,
		slidesToScroll: 1,
		infinite: false,
		dots: false,
		arrows: false,
		focusOnSelect: false,
		accessibility: false,
		centerMode: false,
		centerPadding: '0'
	};

	// Merge user params with defaults (user params override defaults)
	const slickConfig = $.extend({}, defaultParams, carouselParams);

	// Initialize Slick carousel with merged configuration
	$(carouselPrefix + '-carousel').slick(slickConfig);

	// Swipe indicator functionality (if enabled)
	let hasInteracted = false;
	const hideSwipeIndicator = function() {
		if (!hasInteracted && swipeIndicatorEnabled) {
			$('.swipe-indicator').addClass('hidden');
			hasInteracted = true;
		}
	};

	// Custom navigation for prev button
	$(carouselPrefix + '-prev').on('click', function() {
		$(carouselPrefix + '-carousel').slick('slickPrev');
		if (swipeIndicatorEnabled) hideSwipeIndicator();
	});

	// Custom navigation for next button
	$(carouselPrefix + '-next').on('click', function() {
		$(carouselPrefix + '-carousel').slick('slickNext');
		if (swipeIndicatorEnabled) hideSwipeIndicator();
	});

	// Custom navigation for dot indicators
	$(carouselPrefix + '-dots .nav-dot').on('click', function() {
		const slideIndex = $(this).data('slide');
		$(carouselPrefix + '-carousel').slick('slickGoTo', slideIndex);
		if (swipeIndicatorEnabled) hideSwipeIndicator();
	});

	// Update active dot when slide changes
	$(carouselPrefix + '-carousel').on('beforeChange', function(event, slick, currentSlide, nextSlide) {
		$(carouselPrefix + '-dots .nav-dot').removeClass('active');
		$(carouselPrefix + '-dots .nav-dot[data-slide="' + nextSlide + '"]').addClass('active');
		if (swipeIndicatorEnabled) hideSwipeIndicator();
	});

	// Prevent carousel from triggering scroll events that affect sticky CTA
	$(carouselPrefix + '-carousel').on('beforeChange afterChange', function(event, slick, currentSlide, nextSlide) {
		event.stopPropagation();
	});

	// Hide swipe indicator on touch/swipe events (if enabled)
	if (swipeIndicatorEnabled) {
		$(carouselPrefix + '-carousel').on('touchstart swipe', hideSwipeIndicator);
	}
}

// Make function available globally (for non-bundled usage)
if (typeof window !== 'undefined') {
	window.initCarousel = initCarousel;
}

// ES module export (for bundled usage)
export { initCarousel };

