@use '../variables/layout' as layout;

/**
 * ------------------------------------------------------------
 * Visibility Breakpoints
 * ------------------------------------------------------------
 */
.mobile-only {
	display: none;
	@media #{layout.$small-screen-only} {
		display: block;
	}
}
.tablet-only {
	display: none;
	@media #{layout.$medium-screen-only} {
		display: block;
	}
}
.tablet-and-larger-only {
	display: none;
	@media #{layout.$medium-screen-and-larger} {
		display: block;
	}
}
.tablet-and-smaller-only {
	display: none;
	@media #{layout.$medium-screen-and-smaller} {
		display: block;
	}
}
.desktop-only {
	display: none;
	@media #{layout.$large-screen-and-larger} {
		display: block;
	}
}

/**
 * ------------------------------------------------------------
 * HTML & Body
 * ------------------------------------------------------------
 */
html {
	overflow-x: hidden;
	z-index: layout.$z-default;
}

body {
	width: 100%;
	max-width: 100vw;
	overflow-x: hidden;
}

/**
 * ------------------------------------------------------------
 * Grid
 * ------------------------------------------------------------
 */
.grid {
	display: grid;
	gap: 1rem;
	grid-template-columns: 1fr;
	grid-template-rows: auto;
}

.grid-2-col {
	grid-template-columns: 50% 50%;

	@media #{layout.$medium-screen-and-smaller} {
		grid-template-columns: 1fr;
	}
}

/**
 * ------------------------------------------------------------
 * Flex
 * ------------------------------------------------------------
 */
.flex {
	display: flex;
}

.flex-col {
	flex-direction: column;
}

.flex-row {
	flex-direction: row;
}

