   289→/**
   290→ * =============================
   291→ * ACCORDION FUNCTIONALITY
   292→ * =============================
   293→ */
   294→
   295→function initAccordion() {
   296→	const acc = document.getElementsByClassName("accordion-slide");
   297→
   298→	if (!acc || acc.length === 0) {
   299→		return;
   300→	}
   301→
   302→	const toggleAccordion = (e) => {
   303→		let target = e.currentTarget;
   304→		if (!target.classList.contains("active")) {
   305→			Array.from(acc).forEach((slide) => {
   306→				slide.classList.remove("active");
   307→				slide.children[1].style.display = "none";
   308→			});
   309→			target.classList.add("active");
   310→			target.children[1].style.display = "block";
   311→		} else {
   312→			target.classList.remove("active");
   313→			target.children[1].style.display = "none";
   314→		}
   315→	};
   316→
   317→	Array.from(acc).forEach((slide) => {
   318→		slide.addEventListener("click", (e) => toggleAccordion(e));
   319→	});
   320→}
   321→
   322→/**
   323→ * =============================
   324→ * REVIEWS EXPAND/COLLAPSE
   325→ * =============================
   326→ */
   327→
   328→function initReviewsExpand() {
   329→	const buttons = document.querySelectorAll('.quote-attribution');
   330→	
   331→	buttons.forEach(button => {
   332→		button.addEventListener('click', function() {
   333→			let dots = this.parentNode.querySelector('#dots');
   334→			let moreText = this.parentNode.querySelector('#more');
   335→			
   336→			if (dots && moreText) {
   337→				if (dots.style.display === "none") {
   338→					dots.style.display = "inline";
   339→					this.innerHTML = "Read more";
   340→					moreText.style.display = "none";
   341→				} else {
   342→					dots.style.display = "none";
   343→					this.innerHTML = "Read less";
   344→					moreText.style.display = "inline";
   345→				}
   346→			}
   347→		});
   348→	});
   349→}
   350→
   351→/**
   352→ * =============================
   353→ * INITIALIZATION
   354→ * =============================
   355→ */
   356→
   357→// Initialize quiz immediately
   358→initQuiz();
