   361→if (document.readyState === 'loading') {
   362→	document.addEventListener('DOMContentLoaded', () => {
   363→		initCarousels();
   364→		initAccordion();
   365→		initReviewsExpand();
   366→	});
   367→} else {
   368→	initCarousels();
   369→	initAccordion();
   370→	initReviewsExpand();
   371→}
