.quiz-longform .image-text-pair .lead {
	font-size: 1rem;
	line-height: 1.5;
	margin-top: 0;
}

@media (min-width:1024px) {
	.quiz-longform .image-text-pair .lead {
		margin-top: 1rem;
	}
}

.reviews-carousel-women {
	background-color: #d2cec4;
}

.reviews-carousel-women .carousel .review {
	display: flex;
	flex-direction: column;
	align-items: flex-start;
	position: relative;
	padding: 0;
	transition: min-height 0.7s ease-in-out;
}

.reviews-carousel-women .carousel .review img {
	position: absolute;
	right: 1rem;
	top: 2rem;
	z-index: 2;
}

.reviews-carousel-women .carousel .review-collapsed {
	min-height: 25rem;
}

@media (min-width:768px) {
	.reviews-carousel-women .carousel .review-collapsed {
		min-height: 28rem;
	}
}

@media (min-width:1280px) {
	.reviews-carousel-women .carousel .review-collapsed {
		min-height: 25rem;
	}
}

.reviews-carousel-women .carousel .review.expanded {
	min-height: auto;
}

.reviews-carousel-women .carousel .review.expanded .quote-block {
	padding-bottom: 4rem;
}

.reviews-carousel-women .carousel .media-block {
	display: none;
}

