];

const quizResultContent = [
	{
		"header": "We've got you covered.",
		"body": "You deserve to understand what's happening with your body, and Hone's got your back. Your licensed doctor will guide you through everything, from hormone balancing basics to creating a custom plan that fits your life. No more guesswork, just real answers."
	},
	{
		"header": "Get to know more with our licensed physicians.",
		"body": "You've got questions, and we've got answers. Dive deeper into how balancing your hormones can kick menopause symptoms to the curb and help you thrive. Our doctors will take you through the whole process, from symptom relief to long-term wellness—tailored just for you."
	},
	{
		"header": "Hone in on your health.",
		"body": "You've done your research, now let's see if Hone can work for you. Ready to feel more energized, focused, and back in control?<br/>Order your comprehensive blood test and get started on your personalized plan."
	}
];

/**
 * =============================
 * QUIZ FUNCTIONALITY
 * =============================
 */

function initQuiz() {
	const questionElement = document.getElementById("question");
	const optionsElement = document.getElementById("options");
	const questionContainer = document.getElementsByClassName("question-container")[0];
	const resultsContainer = document.getElementsByClassName("results-container")[0];
	const progress = document.getElementsByClassName("progress")[0];

	if (!questionElement || !optionsElement || !questionContainer || !resultsContainer || !progress) {
		return;
	}

	let currentQuestion = 0;

	function showQuestion() {
		const question = quizData[currentQuestion];
		questionContainer.classList.remove('question' + '-' + (question.id - 1));
		questionContainer.classList.add('question' + '-' + question.id);
		questionElement.innerText = question.title;
		optionsElement.innerHTML = "";

		question.options.forEach(option => {
			const button = document.createElement("button");
			button.innerText = option.value;
			button.classList.add('option-button', 'single-select');
			button.setAttribute('data-answer', option.id);
			optionsElement.appendChild(button);
			button.addEventListener("click", selectAnswer);
		});
	}

	function bindClickEvents() {
		let ctaButtons = document.getElementsByClassName('quiz-end-cta');
		if (ctaButtons) {
			Array.from(ctaButtons).forEach((button) => {
				button.addEventListener("click", (e) => {
					if (typeof trackQuizEvent === 'function') {
						trackQuizEvent('last_question', e.target.innerText);
					}
				});
			});
		}
	}

	function selectAnswer(e) {
		if (typeof trackQuizEvent === 'function') {
			trackQuizEvent('Q' + (currentQuestion + 1), e.target.innerText);
		}

		let answer = e.target.dataset.answer;
		let width = progress.style.width.replace("%", "");
		width = parseInt(width);
		width = width + 11.9 + "%";
		progress.style.width = width;

		currentQuestion++;

		if (currentQuestion < quizData.length) {
			showQuestion();
		} else {
			resultsContainer.innerHTML +=
				`<div class="results-content">
					<h2>` + quizResultContent[answer].header + `</h2>
					<p>` + quizResultContent[answer].body + `</p>
				</div>
				<div class="options-container">
					<a href="#whats-included" class="btn quiz-end-cta">
					I'm Ready To Start
					</a>
					<a href="#treatment-with-hone" class="option-button quiz-end-cta">
					Still Thinking About it
					</a>
				</div>`;
			bindClickEvents();
			showResult();
		}
	}

	function showResult() {
		questionContainer.style.display = 'none';
		resultsContainer.style.display = 'flex';
	}

	showQuestion();
}

/**
 * =============================
 * CAROUSELS INITIALIZATION
 * =============================
 */

function initCarousels() {
	if (typeof jQuery === 'undefined') {
		return;
	}

	jQuery(document).ready(function($) {
		// Reviews carousel
		$('.carousel').slick({
			slidesToShow: 3,
			infinite: false,
			slidesToScroll: 1,
			dots: true,
			arrows: true,
			responsive: [
				{
					breakpoint: 768,
					settings: {
						slidesToShow: 1,
						slidesToScroll: 1
					}
				},
				{
					breakpoint: 1280,
					settings: {
						slidesToShow: 2,
						slidesToScroll: 1
					}
				}
			]
		});

		// Product actions carousel
		$('.product-actions-slick').slick({
			responsive: [
				{
					breakpoint: 9999,
					settings: "unslick",
				},
				{
					breakpoint: 1280,
					settings: {
						dots: true,
						slidesToShow: 2,
						slidesToScroll: 1
					}
				},
				{
					breakpoint: 768,
					settings: {
						dots: true,
						slidesToShow: 1,
						slidesToScroll: 1,
					}
				},
			]
		});

		$(window).on('resize', function() {
			$('.product-actions-slick').slick('resize');
		});
	});
}

/**
 * =============================
 * ACCORDION FUNCTIONALITY
 * =============================
 */

function initAccordion() {
	const acc = document.getElementsByClassName("accordion-slide");

	if (!acc || acc.length === 0) {
		return;
	}

	const toggleAccordion = (e) => {
		let target = e.currentTarget;
		if (!target.classList.contains("active")) {
			Array.from(acc).forEach((slide) => {
				slide.classList.remove("active");
				slide.children[1].style.display = "none";
			});
			target.classList.add("active");
			target.children[1].style.display = "block";
		} else {
			target.classList.remove("active");
			target.children[1].style.display = "none";
		}
	};

	Array.from(acc).forEach((slide) => {
		slide.addEventListener("click", (e) => toggleAccordion(e));
	});
}

/**
 * =============================
 * REVIEWS EXPAND/COLLAPSE
 * =============================
 */

function initReviewsExpand() {
	const buttons = document.querySelectorAll('.quote-attribution');

	buttons.forEach(button => {
		button.addEventListener('click', function() {
			let dots = this.parentNode.querySelector('#dots');
			let moreText = this.parentNode.querySelector('#more');

			if (dots && moreText) {
				if (dots.style.display === "none") {
					dots.style.display = "inline";
					this.innerHTML = "Read more";
					moreText.style.display = "none";
				} else {
					dots.style.display = "none";
					this.innerHTML = "Read less";
					moreText.style.display = "inline";
				}
			}
		});
	});
}

/**
 * =============================
 * INITIALIZATION
 * =============================
 */

// Initialize quiz immediately
initQuiz();

// Initialize when DOM is ready
if (document.readyState === 'loading') {
	document.addEventListener('DOMContentLoaded', () => {
		initCarousels();
		initAccordion();
		initReviewsExpand();
	});
} else {
	initCarousels();
	initAccordion();
	initReviewsExpand();
}

